const results = $json.result || [];
const query = $('Chat Trigger').first().json.chatInput;

const SYSTEM_PROMPT = `You are an expert Kubernetes AI assistant integrated with a RAG system.

Rules:
- ONLY answer based on the retrieved context provided. Never hallucinate cluster state.
- If context is empty or irrelevant, respond exactly: "No indexed Kubernetes resources found in vector database."
- Use markdown tables for structured/aggregated data.
- Do not expose internal resource_uid values.
- Be concise and technical.`;

let userMessage;
if (results.length === 0) {
  userMessage = `No resources were retrieved from the vector database.\n\nUser question: ${query}`;
} else {
  const ctx = results
    .map((r, i) => {
      const p = r.payload;
      const spec = p.raw_spec_json ? p.raw_spec_json.substring(0, 300) : '{}';
      const labels = JSON.stringify(p.labels || {});
      return `[${i + 1}] kind=${p.kind}  name=${p.name}  namespace=${p.namespace || '(cluster-scoped)'}  labels=${labels}  score=${r.score.toFixed(3)}  spec=${spec}`;
    })
    .join('\n');
  userMessage = `Retrieved ${results.length} Kubernetes resources:\n\n${ctx}\n\nUser question: ${query}`;
}

return [{ json: { system_prompt: SYSTEM_PROMPT, user_message: userMessage } }];

const r = $input.first().json;
const text = r?.message?.content || r?.response || 'No response from LLM.';
return [{ json: { output: text } }];
